```ts
// Performance monitoring loop
setInterval(() => {
  getCPUUsage((usage) => {
    const percent = (usage * 100).toFixed(1);
    console.log(`[${new Date().toISOString()}] CPU: ${percent}%`);
  });
}, 5000);

```

